import React from 'react';
import { Card, Stack, Text, Heading, Divider, Spacer } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = "Unknown City",
    temperature = 0,
    condition = "Unknown",
    humidity = 0,
    windSpeed = 0,
    unit = "C",
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={3}>{city}</Heading>
          <Text variant="overline" color="var(--ggui-color-neutral-500, #6b7280)">CURRENT</Text>
        </Stack>

        <Stack direction="horizontal" align="center" justify="between" gap={32}>
          <Stack gap={4}>
            <Heading level={1}>{temperature}°{unit}</Heading>
            <Text variant="bodyLarge" weight="medium">{condition}</Text>
          </Stack>

          <Stack gap={8} align="end">
            <Text variant="bodySmall" color="var(--ggui-color-neutral-600, #4b5563)">Humidity: {humidity}%</Text>
            <Text variant="bodySmall" color="var(--ggui-color-neutral-600, #4b5563)">Wind: {windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider />

        <Stack direction="horizontal" justify="between" align="center" gap={16}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="caption" weight="semibold">{item.day ?? "--"}</Text>
              <Text size="2xl">{item.icon ?? "❓"}</Text>
              <Stack direction="horizontal" gap={8}>
                <Text variant="bodySmall" weight="bold">{item.high ?? 0}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{item.low ?? 0}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState } from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Progress,
  Box,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = [
      "Dashboard Analytics",
      "Team Collaboration",
      "API Integration",
      "Custom Workflows",
      "Mobile App",
      "AI Assistance"
    ],
    satisfactionLabels = [
      "Very Unsatisfied",
      "Unsatisfied",
      "Neutral",
      "Satisfied",
      "Very Satisfied"
    ],
    onSubmit,
  } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  const validateEmail = (email: string) => /\S+@\S+\.\S+/.test(email);

  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);
  const isStep2Valid = formData.satisfaction > 0;
  const isStep3Valid = formData.features.length > 0;

  const handleNext = () => {
    if (step < 5) setStep(step + 1);
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
  };

  const handleSubmit = () => {
    onSubmit?.(formData);
  };

  const progress = ((step - 1) / 4) * 100;

  return (
    <Card padding={24} shadow="md">
      <Stack gap={16}>
        <Stack gap={8}>
          <Heading level={3}>Customer Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">Step {step} of 5</Text>
          <Progress value={progress} size="sm" />
        </Stack>

        <Divider />

        {step === 1 && (
          <Stack gap={16}>
            <Input
              label="Name"
              required
              value={formData.name}
              onChange={(v) => setFormData({ ...formData, name: v })}
              error={!formData.name && step > 1 ? "Name is required" : ""}
            />
            <Input
              label="Email"
              required
              type="email"
              value={formData.email}
              onChange={(v) => setFormData({ ...formData, email: v })}
              error={!validateEmail(formData.email) && step > 1 ? "Valid email required" : ""}
            />
          </Stack>
        )}

        {step === 2 && (
          <RadioGroup
            label="How satisfied are you with our service?"
            value={String(formData.satisfaction)}
            onChange={(v) => setFormData({ ...formData, satisfaction: Number(v) })}
            options={satisfactionLabels.map((label, i) => ({
              value: String(i + 1),
              label: label,
            }))}
          />
        )}

        {step === 3 && (
          <Stack gap={8}>
            <Text variant="label">Which features interest you?</Text>
            {featureOptions.map((feature) => (
              <Checkbox
                key={feature}
                label={feature}
                checked={formData.features.includes(feature)}
                onChange={(checked) => {
                  const updated = checked
                    ? [...formData.features, feature]
                    : formData.features.filter((f) => f !== feature);
                  setFormData({ ...formData, features: updated });
                }}
              />
            ))}
          </Stack>
        )}

        {step === 4 && (
          <TextArea
            label="Additional Comments (optional)"
            rows={4}
            maxLength={500}
            showCount
            value={formData.comments}
            onChange={(v) => setFormData({ ...formData, comments: v })}
          />
        )}

        {step === 5 && (
          <Stack gap={12}>
            <Heading level={4}>Review your answers</Heading>
            <Box padding={16} background="var(--ggui-color-neutral-100)" borderRadius={8}>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Satisfaction: {satisfactionLabels[formData.satisfaction - 1] ?? 'None'}</Text>
              <Text>Features: {formData.features.join(', ') || 'None'}</Text>
              <Text>Comments: {formData.comments || 'None'}</Text>
            </Box>
          </Stack>
        )}

        <Stack direction="horizontal" justify="between" gap={16}>
          <Button variant="secondary" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < 5 ? (
            <Button
              onClick={handleNext}
              disabled={
                (step === 1 && !isStep1Valid) || 
                (step === 2 && !isStep2Valid) || 
                (step === 3 && !isStep3Valid)
              }
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>Submit Survey</Button>
          )}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Button, Input, Select, Divider } from '@ggui-ai/design/primitives';
import { FormField } from '@ggui-ai/design/components';

interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>;
  onTaskUpdate?: (payload: { action: string; taskId: string; data: any }) => void;
}

export default function GeneratedComponent({ tasks = [], columns = [], onTaskUpdate }: Props) {
  const [taskList, setTaskList] = useState(tasks);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: '??',
    };
    setTaskList([...taskList, newTask]);
    onTaskUpdate?.({ action: 'create', taskId: newTask.id, data: newTask });
    setNewTaskTitle('');
    setIsAdding(null);
  };

  const moveTask = (taskId: string, targetColumn: string) => {
    setTaskList(prev => prev.map(t => t.id === taskId ? { ...t, column: targetColumn } : t));
    onTaskUpdate?.({ action: 'move', taskId, data: { column: targetColumn } });
  };

  return (
    <Stack direction="horizontal" gap={24} align="start" padding={24}>
      {columns.map(col => {
        const colTasks = taskList.filter(t => t.column === col.id);
        return (
          <Card key={col.id} padding={16} style={{ minWidth: 300 }}>
            <Stack gap={16}>
              <Text variant="label" weight="bold">{col.name} ({colTasks.length})</Text>
              <Stack gap={8}>
                {colTasks.map(task => (
                  <Card key={task.id} padding={12} shadow="sm">
                    <Stack gap={8}>
                      <Text variant="bodySmall">{task.title}</Text>
                      <Stack direction="horizontal" gap={8} justify="between">
                        <Text variant="caption">{task.priority?.toUpperCase()}</Text>
                        <Select 
                          value={col.id ?? ''} 
                          onChange={(val) => moveTask(task.id!, val)}
                          options={columns.map(c => ({ value: c.id!, label: `Move to ${c.name}` }))}
                        />
                      </Stack>
                    </Stack>
                  </Card>
                ))}
              </Stack>
              {isAdding === col.id ? (
                <Stack gap={8}>
                  <Input label="Task Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                  <Button variant="primary" onClick={() => handleAddTask(col.id!)}>Add Task</Button>
                  <Button variant="ghost" onClick={() => setIsAdding(null)}>Cancel</Button>
                </Stack>
              ) : (
                <Button variant="outline" onClick={() => setIsAdding(col.id!)}>+ Add Task</Button>
              )}
            </Stack>
          </Card>
        );
      })}
    </Stack>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Box, 
  Heading, 
  Spacer 
} from '@ggui-ai/design/primitives';
import { Input } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements?: Array<ElementData>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-200, #bae6fd)',
  'noble-gas': 'var(--ggui-color-success-200, #bbf7d0)',
  'alkali-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'alkaline-earth-metal': 'var(--ggui-color-info-200, #a5f3fc)',
  'transition-metal': 'var(--ggui-color-neutral-200, #e5e7eb)',
  'post-transition-metal': 'var(--ggui-color-neutral-300, #d1d5db)',
  'metalloid': 'var(--ggui-color-primary-100, #e0f2fe)',
  'halogen': 'var(--ggui-color-error-200, #fecaca)',
  'lanthanide': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'actinide': 'var(--ggui-color-neutral-100, #f3f4f6)',
  'default': 'var(--ggui-color-neutral-100, #f3f4f6)'
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = elements.filter(el => 
    el.name?.toLowerCase().includes(search.toLowerCase()) || 
    el.symbol?.toLowerCase().includes(search.toLowerCase())
  );

  const categories = Array.from(new Set(elements.map(e => e.category || 'default')));

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Box>
          <Input 
            label="Search Elements" 
            placeholder="Search by name or symbol"
            value={search} 
            onChange={setSearch} 
            type="search"
          />
        </Box>

        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, 1fr)', 
            gap: 'var(--ggui-spacing-1, 4px)',
            alignItems: 'start'
          }}
        >
          {filteredElements.map((el) => (
            <div
              key={el.atomicNumber}
              onClick={() => setSelectedElement(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                cursor: 'pointer',
                aspectRatio: '1',
                padding: 'var(--ggui-spacing-1, 4px)',
                background: CATEGORY_COLORS[el.category || 'default'] || CATEGORY_COLORS.default,
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center',
                opacity: search && !el.name?.toLowerCase().includes(search.toLowerCase()) && !el.symbol?.toLowerCase().includes(search.toLowerCase()) ? 0.2 : 1
              }}
            >
              <Text variant="caption" style={{ alignSelf: 'flex-start' }}>{el.atomicNumber}</Text>
              <Heading level={4}>{el.symbol}</Heading>
            </div>
          ))}
        </Box>

        <Card padding="var(--ggui-spacing-4, 16px)">
          <Heading level={3}>Legend</Heading>
          <Spacer size="var(--ggui-spacing-2, 8px)" />
          <Stack direction="horizontal" wrap gap="var(--ggui-spacing-2, 8px)">
            {categories.map(cat => (
              <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-1, 4px)">
                <Box style={{ width: 12, height: 12, background: CATEGORY_COLORS[cat] || CATEGORY_COLORS.default, borderRadius: 2 }} />
                <Text variant="caption">{cat}</Text>
              </Stack>
            ))}
          </Stack>
        </Card>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={2}>{selectedElement.name}</Heading>
              <Text>Symbol: {selectedElement.symbol}</Text>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text>Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, Card, Stack, Box, Text, Heading, 
  Button, Badge 
} from '@ggui-ai/design/primitives';

interface Props {
  product?: { 
    id?: string; 
    name?: string; 
    price?: number; 
    currency?: string; 
    rating?: number; 
    reviewCount?: number; 
    stock?: number; 
    description?: string; 
    specifications?: Array<{ key: string; value: string }>; 
    reviews?: Array<{ author: string; rating: number; text: string; date: string }>; 
  };
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { product = {} } = props;
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState<'description' | 'specs' | 'reviews'>('description');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const {
    id = 'prod-001',
    name = 'Wireless Headphones',
    price = 0,
    currency = 'USD',
    rating = 0,
    reviewCount = 0,
    stock = 0,
    description = '',
    specifications = [],
    reviews = []
  } = product;

  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;

  const handleAddToCart = async () => {
    if (props.onAddToCart) {
      setIsSubmitting(true);
      await props.onAddToCart({ productId: id, quantity });
      setIsSubmitting(false);
    }
  };

  const renderStars = (r: number) => (
    <Stack direction="horizontal" gap={2}>
      {[1, 2, 3, 4, 5].map((i) => (
        <Text key={i} color={i <= Math.round(r) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-neutral-300)'}>
          ★
        </Text>
      ))}
    </Stack>
  );

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={32}>
        <Stack direction="horizontal" gap={32} wrap>
          <Box borderRadius={12} background="var(--ggui-color-surfaceVariant)" padding={40} style={{ flex: 1, minWidth: 300, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Heading level={2} align="center">{name}</Heading>
          </Box>

          <Stack gap={16} style={{ flex: 1, minWidth: 300 }}>
            <Heading level={1}>{name}</Heading>
            <Text variant="bodyLarge" weight="bold">{currency} {price.toFixed(2)}</Text>

            <Stack direction="horizontal" align="center" gap={8}>
              {renderStars(rating)}
              <Text variant="caption">({reviewCount} reviews)</Text>
            </Stack>

            <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}>
              {isOutOfStock ? 'Out of Stock' : isLowStock ? `Low Stock (${stock} left)` : 'In Stock'}
            </Badge>
          </Stack>
        </Stack>

        <Card padding={24}>
          <Stack direction="horizontal" gap={16} style={{ marginBottom: 16 }}>
            <Button variant={activeTab === 'description' ? 'primary' : 'ghost'} onClick={() => setActiveTab('description')}>Description</Button>
            <Button variant={activeTab === 'specs' ? 'primary' : 'ghost'} onClick={() => setActiveTab('specs')}>Specifications</Button>
            <Button variant={activeTab === 'reviews' ? 'primary' : 'ghost'} onClick={() => setActiveTab('reviews')}>Reviews</Button>
          </Stack>

          {activeTab === 'description' && <Text>{description}</Text>}

          {activeTab === 'specs' && (
            <Stack gap={8}>
              {(specifications as any[]).map((spec: any, idx: number) => (
                <Stack key={idx} direction="horizontal" justify="between">
                  <Text weight="medium">{spec.key}</Text>
                  <Text>{spec.value}</Text>
                </Stack>
              ))}
            </Stack>
          )}

          {activeTab === 'reviews' && (
            <Stack gap={16}>
              {(reviews as any[]).map((rev: any, idx: number) => (
                <Box key={idx} paddingY={8}>
                  <Text weight="semibold">{rev.author}</Text>
                  <Text variant="caption">{rev.date}</Text>
                  {renderStars(rev.rating)}
                  <Text variant="bodySmall" style={{ marginTop: 4 }}>{rev.text}</Text>
                </Box>
              ))}
            </Stack>
          )}
        </Card>

        <Card padding={24}>
          <Stack direction="horizontal" align="center" gap={16}>
            <Stack direction="horizontal" align="center" gap={8}>
              <Button size="sm" variant="secondary" onClick={() => setQuantity(Math.max(1, quantity - 1))}>-</Button>
              <Text style={{ minWidth: 40, textAlign: 'center' }}>{quantity}</Text>
              <Button size="sm" variant="secondary" onClick={() => setQuantity(Math.min(stock, quantity + 1))}>+</Button>
            </Stack>

            <Button 
              disabled={isOutOfStock || isSubmitting} 
              loading={isSubmitting}
              onClick={handleAddToCart}
            >
              {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Box, Text, Heading, Badge, Divider, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    title = "Chat", 
    currentUser = "You", 
    participantCount, 
    messages: initialMessages = [],
    onSendMessage 
  } = props;

  const [messages, setMessages] = useState(initialMessages);
  const [input, setInput] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail?.text) {
        setMessages((prev) => [...prev, { 
          sender: event.detail.sender ?? 'Agent', 
          text: event.detail.text, 
          timestamp: new Date().toISOString() 
        }]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!input.trim()) return;
    const timestamp = new Date().toISOString();
    const newMessage = {
      sender: currentUser,
      text: input,
      timestamp
    };
    setMessages([...messages, newMessage]);
    onSendMessage?.({ text: input, timestamp });
    setInput('');
  };

  return (
    <Card radius="lg" shadow="md" style={{ display: 'flex', flexDirection: 'column', height: '600px', width: '100%', maxWidth: '500px' }}>
      <Box paddingX={16} paddingY={12} background="var(--ggui-color-surfaceVariant)">
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{title}</Heading>
          {participantCount !== undefined && <Badge variant="secondary" size="sm">{participantCount} participants</Badge>}
        </Stack>
      </Box>
      <Divider margin={0} />

      <Box padding={16} style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-4)' }} ref={scrollRef}>
        {messages.map((msg, i) => {
          const isSelf = msg.sender === currentUser;
          const showSender = i === 0 || messages[i-1].sender !== msg.sender;

          return (
            <Stack key={i} align={isSelf ? 'end' : 'start'} gap={4}>
              {showSender && <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{msg.sender}</Text>}
              <Box 
                paddingX={12} 
                paddingY={8} 
                borderRadius={8} 
                background={isSelf ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
              >
                <Text color={isSelf ? '#ffffff' : 'var(--ggui-color-onSurface)'}>{msg.text}</Text>
              </Box>
              <Text variant="caption" size="xs" color="var(--ggui-color-neutral-400)">
                {new Date(msg.timestamp || '').toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </Text>
            </Stack>
          );
        })}
      </Box>

      <Divider margin={0} />
      <Box padding={16}>
        <Stack gap={8}>
          <Text as="label" htmlFor="chat-input" variant="label" style={{ display: 'none' }}>Message</Text>
          <Stack direction="horizontal" gap={8} align="center">
            <Input 
              id="chat-input"
              label=""
              value={input} 
              onChange={setInput} 
              placeholder="Type a message..." 
              onKeyDown={(e: any) => e.key === 'Enter' && handleSend()}
            />
            <Button variant="primary" onClick={handleSend} disabled={!input.trim()}>Send</Button>
          </Stack>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Stack, 
  Text, 
  Heading, 
  Card, 
  Badge, 
  Icon, 
  Spinner 
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks?: Stock[];
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [stocks, setStocks] = useState<Stock[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(props.lastUpdated);

  useEffect(() => {
    const handleEvent = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data?.stocks) setStocks(data.stocks);
      if (data?.lastUpdated) setLastUpdated(data.lastUpdated);
    };

    window.addEventListener('ggui:agent-data', handleEvent as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleEvent as EventListener);
  }, []);

  if (!stocks || stocks.length === 0) {
    return (
      <Container padding={48}>
        <Stack align="center" gap={16}>
          <Spinner size={32} />
          <Text>Loading market data...</Text>
        </Stack>
      </Container>
    );
  }

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          {lastUpdated && (
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Last Updated: {new Date(lastUpdated).toLocaleTimeString()}
            </Text>
          )}
        </Stack>

        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {stocks.map((stock, index) => {
            const change = stock.change ?? 0;
            const isPositive = change >= 0;
            const price = stock.price ?? 0;
            const percent = stock.changePercent ?? 0;

            return (
              <Card key={stock.symbol ?? index} padding={20} shadow="sm">
                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={3}>{stock.symbol ?? 'N/A'}</Heading>
                    <Badge variant={isPositive ? 'success' : 'error'} pill>
                      <Stack direction="horizontal" gap={4} align="center">
                        <Icon name={isPositive ? 'chevron-up' : 'chevron-down'} size={12} />
                        {Math.abs(percent).toFixed(2)}%
                      </Stack>
                    </Badge>
                  </Stack>

                  <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">
                    {stock.name ?? 'Unknown'}
                  </Text>

                  <Heading level={2}>${price.toFixed(2)}</Heading>

                  <Text 
                    variant="label" 
                    color={isPositive ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)'}
                  >
                    {isPositive ? '+' : ''}{change.toFixed(2)}
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Text, 
  Heading, 
  Button, 
  Input, 
  Select, 
  Toggle, 
  Divider, 
  RadioGroup 
} from '@ggui-ai/design/primitives';

interface Props {
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    initialProfile = {}, 
    avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"], 
    roleOptions = ["Developer", "Designer", "Manager", "Other"],
    onComplete 
  } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? avatarOptions[0],
    role: initialProfile.role ?? roleOptions[0],
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light'
  });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={24} shadow="md">
        <Stack gap={16}>
          <Text variant="overline" color="var(--ggui-color-primary-600)">
            Step {step} of 3
          </Text>
          <div style={{ 
            width: '100%', 
            height: '8px', 
            background: 'var(--ggui-color-neutral-200)', 
            borderRadius: '999px', 
            overflow: 'hidden' 
          }}>
            <div style={{ 
              width: `${(step / 3) * 100}%`, 
              height: '100%', 
              background: 'var(--ggui-color-primary-600)', 
              transition: 'width 0.3s' 
            }} />
          </div>

          {step === 1 && (
            <Stack gap={16}>
              <Heading level={2}>Profile Setup</Heading>
              <Input 
                label="Name" 
                required 
                value={formData.name} 
                onChange={(v) => setFormData(prev => ({ ...prev, name: v }))} 
              />
              <Input 
                label="Email" 
                type="email" 
                required 
                value={formData.email} 
                onChange={(v) => setFormData(prev => ({ ...prev, email: v }))} 
                error={formData.email && !validateEmail(formData.email) ? "Invalid email format" : undefined}
              />
              <RadioGroup 
                label="Choose Avatar" 
                value={formData.avatar} 
                onChange={(v) => setFormData(prev => ({ ...prev, avatar: v }))}
                direction="horizontal"
                options={avatarOptions.map(o => ({ value: o, label: o }))} 
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap={16}>
              <Heading level={2}>Preferences</Heading>
              <Select 
                label="Role" 
                value={formData.role} 
                onChange={(v) => setFormData(prev => ({ ...prev, role: v }))} 
                options={roleOptions.map(r => ({ value: r, label: r }))} 
              />
              <Toggle 
                label="Email Notifications" 
                checked={formData.emailNotifications} 
                onChange={(v) => setFormData(prev => ({ ...prev, emailNotifications: v }))} 
              />
              <Toggle 
                label="Dark Theme" 
                checked={formData.theme === 'dark'} 
                onChange={(v) => setFormData(prev => ({ ...prev, theme: v ? 'dark' : 'light' }))} 
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap={16}>
              <Heading level={2}>Review & Confirm</Heading>
              <Stack gap={8} style={{ 
                background: 'var(--ggui-color-neutral-100)', 
                padding: '16px', 
                borderRadius: 'var(--ggui-shape-radius-md)' 
              }}>
                <Text><strong>Name:</strong> {formData.name}</Text>
                <Text><strong>Email:</strong> {formData.email}</Text>
                <Text><strong>Avatar:</strong> {formData.avatar}</Text>
                <Text><strong>Role:</strong> {formData.role}</Text>
                <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'On' : 'Off'}</Text>
                <Text><strong>Theme:</strong> {formData.theme}</Text>
              </Stack>
            </Stack>
          )}

          <Divider margin={8} />

          <Stack direction="horizontal" justify="between">
            <Button 
              variant="secondary" 
              onClick={() => setStep(s => s - 1)} 
              disabled={step === 1}
            >
              Go Back
            </Button>
            {step < 3 ? (
              <Button 
                onClick={() => setStep(s => s + 1)} 
                disabled={step === 1 ? !isStep1Valid : false}
              >
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(formData)}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React from 'react';
import { Card, Stack, Heading, Text, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard component displays high-level weather metrics and a multi-day forecast.
 * Uses semantic design tokens for theme compatibility and flexible layout primitives.
 */
export default function GeneratedComponent({
  city = "Tokyo",
  temperature = 28,
  condition = "Sunny",
  humidity = 45,
  windSpeed = 8,
  unit = "C",
  forecast = [
    { day: "Mon", icon: "☀️", high: 30, low: 22 },
    { day: "Tue", icon: "⛅", high: 27, low: 20 },
    { day: "Wed", icon: "🌧️", high: 24, low: 18 },
    { day: "Thu", icon: "⛅", high: 26, low: 19 },
    { day: "Fri", icon: "☀️", high: 29, low: 21 }
  ]
}: Props) {
  // Simple heuristic for dynamic icon selection if no specific logic is provided in data
  const getConditionEmoji = (cond: string) => {
    const val = cond?.toLowerCase() ?? "";
    if (val.includes("sun") || val.includes("clear")) return "☀️";
    if (val.includes("cloud")) return "☁️";
    if (val.includes("rain") || val.includes("shower")) return "🌧️";
    if (val.includes("snow")) return "❄️";
    if (val.includes("storm") || val.includes("thunder")) return "⛈️";
    return "🌡️";
  };

  return (
    <Card 
      padding={24} 
      radius="xl" 
      shadow="md" 
      border={true}
      style={{
        background: 'var(--ggui-color-surface, #fafafa)',
        width: '100%',
        maxWidth: '480px'
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Current City and Main Icon */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack direction="vertical" gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city ?? "Unknown Location"}
            </Heading>
            <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition ?? "Unknown Condition"}
            </Text>
          </Stack>
          <Box padding={8} borderRadius="var(--ggui-shape-radius-md, 8px)">
            <Text size="4xl" align="right">
              {getConditionEmoji(condition)}
            </Text>
          </Box>
        </Stack>

        {/* Current Temp and Secondary Metrics */}
        <Stack direction="horizontal" justify="between" align="end">
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-onSurface, #18181b)"
            style={{ fontSize: 'var(--ggui-font-size-4xl, 48px)' }}
          >
            {temperature ?? 0}°{unit ?? "C"}
          </Text>
          <Stack direction="vertical" gap={4} align="end">
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {humidity ?? 0}%
              </Text>
            </Stack>
            <Stack direction="horizontal" gap={8} align="center">
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
              <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed ?? 0} km/h
              </Text>
            </Stack>
          </Stack>
        </Stack>

        <Divider 
          color="var(--ggui-color-outlineVariant, #e4e4e7)" 
          margin="0" 
        />

        {/* 5-Day Forecast Grid */}
        <Stack direction="horizontal" justify="between" align="stretch">
          {forecast?.map((item, idx) => (
            <Stack 
              key={`${item.day}-${idx}`} 
              direction="vertical" 
              gap={12} 
              align="center"
              style={{ flex: 1 }}
            >
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day ?? "---"}
              </Text>

              <Text size="xl">
                {item.icon ?? "🌡️"}
              </Text>

              <Stack direction="vertical" gap={2} align="center">
                <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  {item.high ?? 0}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {item.low ?? 0}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Heading,
  Text,
  Input,
  TextArea,
  RadioGroup,
  Checkbox,
  Button,
  Progress,
  Divider,
  Spacer,
  Alert
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions?: string[];
  /** Labels for satisfaction rating (1 to 5) */
  satisfactionLabels?: string[];
  /** Callback for submission */
  onSubmit?: (data: SurveyData) => void;
}

interface SurveyData {
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
}

export default function GeneratedComponent({
  featureOptions = [
    "Dashboard Analytics",
    "Team Collaboration",
    "API Integration",
    "Custom Workflows",
    "Mobile App",
    "AI Assistance"
  ],
  satisfactionLabels = [
    "Very Unsatisfied",
    "Unsatisfied",
    "Neutral",
    "Satisfied",
    "Very Satisfied"
  ],
  onSubmit
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: 0,
    features: [],
    comments: ''
  });
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const totalSteps = 5;

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const handleNext = () => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!formData.name.trim()) newErrors.name = 'Name is required';
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!validateEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
    }

    if (step === 2 && formData.satisfaction === 0) {
      newErrors.satisfaction = 'Please select a rating';
    }

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    setErrors({});
    setStep((s) => Math.min(s + 1, totalSteps));
  };

  const handleBack = () => {
    setStep((s) => Math.max(s - 1, 1));
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) {
        await onSubmit(formData);
      }
      setIsSuccess(true);
    } catch (err) {
      console.error(err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const toggleFeature = (feature: string, checked: boolean) => {
    setFormData((prev) => ({
      ...prev,
      features: checked 
        ? [...prev.features, feature] 
        : prev.features.filter((f) => f !== feature)
    }));
  };

  if (isSuccess) {
    return (
      <Container maxWidth="md" padding={24}>
        <Card shadow="md" padding={40} radius="xl">
          <Stack align="center" gap={20}>
            <Box 
              background="var(--ggui-color-success-100, #dcfce7)" 
              padding={16} 
              borderRadius="var(--ggui-shape-radius-full, 9999px)"
            >
              <Text color="var(--ggui-color-success-600, #16a34a)" weight="bold" size="2xl">✓</Text>
            </Box>
            <Heading level={2} align="center">Thank You!</Heading>
            <Text align="center" color="var(--ggui-color-onSurfaceVariant)">
              Your feedback has been successfully submitted. We appreciate your time!
            </Text>
            <Button variant="outline" onClick={() => window.location.reload()}>
              Submit Another Response
            </Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="end">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {step} of {totalSteps}
            </Text>
            <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-600)">
              {Math.round((step / totalSteps) * 100)}% Complete
            </Text>
          </Stack>
          <Progress 
            value={step} 
            max={totalSteps} 
            variant="default" 
            size="sm" 
          />
        </Stack>

        <Card shadow="md" padding={32} radius="xl" border={true}>
          <Stack gap={32}>
            {step === 1 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={3}>Basic Information</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Please introduce yourself so we can link your feedback to your account.
                  </Text>
                </Stack>
                <Input
                  label="Full Name"
                  placeholder="e.g. John Doe"
                  value={formData.name}
                  onChange={(val) => setFormData({ ...formData, name: val })}
                  error={errors.name}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="john@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData({ ...formData, email: val })}
                  error={errors.email}
                  required
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={3}>Satisfaction Rating</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    How would you rate your overall experience with our platform?
                  </Text>
                </Stack>
                <RadioGroup
                  label="Level of Satisfaction"
                  value={String(formData.satisfaction)}
                  onChange={(val) => setFormData({ ...formData, satisfaction: Number(val) })}
                  error={errors.satisfaction}
                  options={satisfactionLabels.map((label, index) => ({
                    value: String(index + 1),
                    label: label,
                    description: `Rating: ${index + 1}`
                  }))}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={3}>Feature Interests</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Which of the following features are most important to your workflow?
                  </Text>
                </Stack>
                <Stack gap={12}>
                  {featureOptions.map((option) => (
                    <Checkbox
                      key={option}
                      label={option}
                      checked={formData.features.includes(option)}
                      onChange={(checked) => toggleFeature(option, checked)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap={20}>
                <Stack gap={4}>
                  <Heading level={3}>Additional Comments</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Anything else you'd like to share? Your feedback helps us improve.
                  </Text>
                </Stack>
                <TextArea
                  label="Your Feedback"
                  placeholder="Share your thoughts here..."
                  value={formData.comments}
                  onChange={(val) => setFormData({ ...formData, comments: val })}
                  maxLength={500}
                  showCount
                  rows={6}
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap={24}>
                <Stack gap={4}>
                  <Heading level={3}>Review Your Answers</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Please double-check your responses before submitting.
                  </Text>
                </Stack>

                <Box 
                  padding={20} 
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)" 
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                >
                  <Stack gap={16}>
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Contact</Text>
                      <Text weight="medium">{formData.name} ({formData.email})</Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                      <Text weight="medium">{satisfactionLabels[formData.satisfaction - 1] ?? 'Not rated'}</Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features</Text>
                      <Stack direction="horizontal" gap={8} wrap>
                        {formData.features.length > 0 ? (
                          formData.features.map(f => (
                            <Box 
                              key={f} 
                              paddingX={8} 
                              paddingY={2} 
                              background="var(--ggui-color-primary-100)" 
                              borderRadius={4}
                            >
                              <Text variant="caption" color="var(--ggui-color-primary-700)" weight="medium">{f}</Text>
                            </Box>
                          ))
                        ) : (
                          <Text variant="bodySmall" color="var(--ggui-color-neutral-400)">None selected</Text>
                        )}
                      </Stack>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                      <Text weight="medium">{formData.comments || 'No comments provided'}</Text>
                    </Stack>
                  </Stack>
                </Box>

                <Alert variant="info" title="Final Step">
                  By submitting, you agree to our privacy policy regarding feedback data.
                </Alert>
              </Stack>
            )}

            <Stack direction="horizontal" justify="between" align="center">
              <Button 
                variant="ghost" 
                onClick={handleBack} 
                disabled={step === 1 || isSubmitting}
              >
                Back
              </Button>

              <Stack direction="horizontal" gap={12}>
                <Spacer size="flex" />
                {step < totalSteps ? (
                  <Button 
                    variant="primary" 
                    onClick={handleNext}
                  >
                    Next
                  </Button>
                ) : (
                  <Button 
                    variant="primary" 
                    onClick={handleSubmit} 
                    loading={isSubmitting}
                  >
                    Submit Survey
                  </Button>
                )}
              </Stack>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Heading,
  Text,
  Badge,
  Button,
  Input,
  Select,
  Avatar,
  Icon,
  Divider,
} from '@ggui-ai/design/primitives';

interface Task {
  id?: string;
  title?: string;
  priority?: 'low' | 'medium' | 'high';
  assignee?: string;
  column?: string;
  dueDate?: string;
}

interface Column {
  id?: string;
  name?: string;
}

interface Props {
  /** Array of tasks with id, title, priority, assignee, column ID, and optional dueDate */
  tasks: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  /** Callback when a task is moved, edited, or created */
  onTaskUpdate?: (payload: { action: string; taskId?: string; data: Partial<Task> }) => void;
}

export default function KanbanBoard({
  tasks: initialTasks = [],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' },
  ],
  onTaskUpdate,
}: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [addingInColumn, setAddingInColumn] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);

  // Form States
  const [addTitle, setAddTitle] = useState('');
  const [addPriority, setAddPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [addError, setAddError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [editTitle, setEditTitle] = useState('');
  const [editPriority, setEditPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editError, setEditError] = useState('');

  useEffect(() => {
    setTasks(initialTasks ?? []);
  }, [initialTasks]);

  const summary = {
    total: tasks.length,
    completed: tasks.filter((t) => t.column === 'done').length,
  };

  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error';
      case 'medium':
        return 'warning';
      case 'low':
      default:
        return 'info';
    }
  };

  const handleMove = (taskId: string, newColumnId: string) => {
    const updatedTasks = tasks.map((t) => (t.id === taskId ? { ...t, column: newColumnId } : t));
    setTasks(updatedTasks);
    onTaskUpdate?.({ action: 'move', taskId, data: { column: newColumnId } });
  };

  const startEdit = (task: Task) => {
    setEditingTaskId(task.id ?? null);
    setEditTitle(task.title ?? '');
    setEditPriority(task.priority ?? 'medium');
    setEditError('');
  };

  const saveEdit = (taskId: string) => {
    if (!editTitle.trim()) {
      setEditError('Title is required');
      return;
    }
    const updatedTasks = tasks.map((t) =>
      t.id === taskId ? { ...t, title: editTitle.trim(), priority: editPriority } : t
    );
    setTasks(updatedTasks);
    onTaskUpdate?.({
      action: 'edit',
      taskId,
      data: { title: editTitle.trim(), priority: editPriority },
    });
    setEditingTaskId(null);
  };

  const saveNewTask = () => {
    if (!addTitle.trim()) {
      setAddError('Title is required');
      return;
    }
    setIsSubmitting(true);
    const newTask: Task = {
      id: `task-${Date.now()}`,
      title: addTitle.trim(),
      priority: addPriority,
      column: addingInColumn ?? 'todo',
      assignee: '??',
    };

    setTasks([...tasks, newTask]);
    onTaskUpdate?.({
      action: 'create',
      taskId: newTask.id,
      data: newTask,
    });

    setIsSubmitting(false);
    setAddingInColumn(null);
    setAddTitle('');
  };

  const columnOptions = columns.map((col) => ({
    value: col.id ?? '',
    label: col.name ?? '',
  }));

  const priorityOptions = [
    { value: 'low', label: 'Low' },
    { value: 'medium', label: 'Medium' },
    { value: 'high', label: 'High' },
  ];

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        {/* Header Summary */}
        <Card padding={16} radius="lg" shadow="sm" border>
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" align="center" gap={12}>
              <Icon name="menu" color="var(--ggui-color-primary-600)" size={24} />
              <Heading level={3}>Project Roadmap</Heading>
            </Stack>
            <Stack direction="horizontal" gap={12}>
              <Badge variant="secondary" size="lg">Total: {summary.total}</Badge>
              <Badge variant="success" size="lg">Completed: {summary.completed}</Badge>
            </Stack>
          </Stack>
        </Card>

        {/* Kanban Board Layout */}
        <Stack direction="horizontal" align="start" gap={20} style={{ overflowX: 'auto', minHeight: '70vh' }}>
          {columns.map((col) => {
            const colTasks = tasks.filter((t) => t.column === col.id);
            return (
              <Box
                key={col.id}
                background="var(--ggui-color-neutral-50, #f9fafb)"
                borderRadius="var(--ggui-shape-radius-xl)"
                padding={16}
                style={{ minWidth: '320px', width: '320px', border: '1px solid var(--ggui-color-neutral-200)' }}
              >
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={5}>{col.name}</Heading>
                    <Badge variant="default" pill>{colTasks.length}</Badge>
                  </Stack>

                  <Stack gap={12}>
                    {colTasks.map((task) => (
                      <Card key={task.id} padding={12} radius="md" shadow="sm" border>
                        {editingTaskId === task.id ? (
                          <Stack gap={12}>
                            <Input
                              label="Task Title"
                              value={editTitle}
                              onChange={setEditTitle}
                              error={editError}
                              autoFocus
                            />
                            <Select
                              label="Priority"
                              value={editPriority}
                              options={priorityOptions}
                              onChange={(val) => setEditPriority(val as any)}
                            />
                            <Stack direction="horizontal" gap={8} justify="end">
                              <Button size="sm" variant="ghost" onClick={() => setEditingTaskId(null)}>Cancel</Button>
                              <Button size="sm" onClick={() => saveEdit(task.id!)}>Save</Button>
                            </Stack>
                          </Stack>
                        ) : (
                          <Stack gap={12}>
                            <Stack direction="horizontal" justify="between" align="start">
                              <Text weight="medium" color="var(--ggui-color-neutral-900)">{task.title}</Text>
                              <Button
                                variant="ghost"
                                size="xs"
                                leftIcon={<Icon name="settings" size={14} />}
                                onClick={() => startEdit(task)}
                              />
                            </Stack>
                            <Stack direction="horizontal" justify="between" align="center">
                              <Badge variant={getPriorityVariant(task.priority)} size="sm">{task.priority}</Badge>
                              {task.dueDate && (
                                <Text variant="caption" color="var(--ggui-color-neutral-500)">{task.dueDate}</Text>
                              )}
                            </Stack>
                            <Divider margin={4} />
                            <Stack direction="horizontal" justify="between" align="center">
                              <Avatar name={task.assignee} size="sm" />
                              <Box style={{ width: '120px' }}>
                                <Select
                                  size="sm"
                                  value={task.column ?? ''}
                                  options={columnOptions}
                                  onChange={(val) => handleMove(task.id!, val)}
                                />
                              </Box>
                            </Stack>
                          </Stack>
                        )}
                      </Card>
                    ))}
                  </Stack>

                  {addingInColumn === col.id ? (
                    <Card padding={12} radius="md" border shadow="md">
                      <Stack gap={12}>
                        <Input
                          label="New Task Title"
                          placeholder="Task name..."
                          value={addTitle}
                          onChange={setAddTitle}
                          error={addError}
                          disabled={isSubmitting}
                          autoFocus
                        />
                        <Select
                          label="Priority"
                          value={addPriority}
                          options={priorityOptions}
                          onChange={(val) => setAddPriority(val as any)}
                          disabled={isSubmitting}
                        />
                        <Stack direction="horizontal" gap={8} justify="end">
                          <Button size="sm" variant="ghost" onClick={() => setAddingInColumn(null)} disabled={isSubmitting}>Cancel</Button>
                          <Button size="sm" onClick={saveNewTask} loading={isSubmitting}>Add</Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="ghost"
                      fullWidth
                      leftIcon={<Icon name="plus" size={16} />}
                      onClick={() => setAddingInColumn(col.id ?? null)}
                    >
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Input,
  Box,
  Badge,
  Spacer,
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const categories = useMemo(
    () => [
      { id: 'nonmetal', label: 'Nonmetal', color: 'var(--ggui-color-success-500, #22c55e)' },
      { id: 'noble-gas', label: 'Noble Gas', color: 'var(--ggui-color-primary-500, #0ea5e9)' },
      { id: 'alkali-metal', label: 'Alkali Metal', color: 'var(--ggui-color-error-500, #ef4444)' },
      { id: 'alkaline-earth-metal', label: 'Alkaline Earth', color: 'var(--ggui-color-warning-500, #f59e0b)' },
      { id: 'metalloid', label: 'Metalloid', color: 'var(--ggui-color-info-500, #06b6d4)' },
      { id: 'halogen', label: 'Halogen', color: 'var(--ggui-color-success-700, #15803d)' },
      { id: 'transition-metal', label: 'Transition Metal', color: 'var(--ggui-color-neutral-500, #6b7280)' },
      { id: 'post-transition-metal', label: 'Post-transition', color: 'var(--ggui-color-neutral-700, #374151)' },
      { id: 'lanthanide', label: 'Lanthanide', color: 'var(--ggui-color-primary-300, #7dd3fc)' },
      { id: 'actinide', label: 'Actinide', color: 'var(--ggui-color-error-300, #fca5a5)' },
    ],
    []
  );

  const filteredElements = useMemo(() => {
    return elements.filter((el) => {
      const search = searchTerm.toLowerCase();
      return (
        el.name?.toLowerCase().includes(search) ||
        el.symbol?.toLowerCase().includes(search)
      );
    });
  }, [elements, searchTerm]);

  const getCategoryColor = (category?: string) => {
    const cat = categories.find((c) => c.id === category);
    return cat?.color ?? 'var(--ggui-color-neutral-200, #e5e7eb)';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack gap="var(--ggui-spacing-4, 16px)">
          <Heading level={1} align="center">
            Periodic Table of Elements
          </Heading>
          <Box paddingX="var(--ggui-spacing-12, 48px)">
            <Input
              label="Search Elements"
              placeholder="Filter by name or symbol (e.g. 'Gold' or 'Au')"
              value={searchTerm}
              onChange={setSearchTerm}
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Stack direction="horizontal" justify="center" wrap gap="var(--ggui-spacing-2, 8px)">
          {categories.map((cat) => (
            <Badge key={cat.id} variant="default" size="sm">
              <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-1, 4px)">
                <Box
                  padding={4}
                  borderRadius="50%"
                  background={cat.color}
                />
                <Text variant="caption">{cat.label}</Text>
              </Stack>
            </Badge>
          ))}
        </Stack>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1, 4px)',
            minHeight: '400px',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-2, 8px)',
          }}
        >
          {filteredElements.map((el) => {
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
            const categoryColor = getCategoryColor(el.category);

            return (
              <Box
                key={el.atomicNumber}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1/1',
                  minWidth: '48px',
                }}
              >
                <button
                  type="button"
                  onClick={() => setSelectedElement(el)}
                  style={{
                    width: '100%',
                    height: '100%',
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    position: 'relative',
                    padding: 'var(--ggui-spacing-1, 4px)',
                    border: isSelected
                      ? '2px solid var(--ggui-color-onSurface, #18181b)'
                      : `1px solid var(--ggui-color-outline, #d4d4d8)`,
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    backgroundColor: categoryColor,
                    cursor: 'pointer',
                    transition: 'transform 150ms ease, box-shadow 150ms ease',
                    boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                    transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1,
                  }}
                >
                  <span
                    style={{
                      position: 'absolute',
                      top: '2px',
                      left: '4px',
                      fontSize: 'var(--ggui-font-size-xs, 10px)',
                      fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                      color: 'var(--ggui-color-onSurface, #18181b)',
                      opacity: 0.8,
                    }}
                  >
                    {el.atomicNumber}
                  </span>
                  <Text
                    weight="bold"
                    size="lg"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {el.symbol}
                  </Text>
                  <Text
                    size="xs"
                    truncate
                    color="var(--ggui-color-onSurface, #18181b)"
                    style={{ opacity: 0.7 }}
                  >
                    {el.name}
                  </Text>
                </button>
              </Box>
            );
          })}
        </Box>

        {/* Detail Panel */}
        {selectedElement ? (
          <Card shadow="lg" padding="var(--ggui-spacing-6, 24px)" radius="xl">
            <Stack direction="horizontal" justify="between" align="start">
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Stack direction="horizontal" align="end" gap="var(--ggui-spacing-2, 8px)">
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    ({selectedElement.symbol})
                  </Text>
                </Stack>
                <Stack direction="horizontal" gap="var(--ggui-spacing-6, 24px)">
                  <Stack gap="0">
                    <Text variant="label">Atomic Number</Text>
                    <Text variant="bodyLarge" weight="bold">
                      {selectedElement.atomicNumber}
                    </Text>
                  </Stack>
                  <Stack gap="0">
                    <Text variant="label">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="bold">
                      {selectedElement.atomicWeight} u
                    </Text>
                  </Stack>
                  <Stack gap="0">
                    <Text variant="label">Category</Text>
                    <Badge variant="primary" size="lg">
                      {selectedElement.category?.replace('-', ' ').toUpperCase()}
                    </Badge>
                  </Stack>
                </Stack>
              </Stack>
              <Box
                padding="var(--ggui-spacing-6, 24px)"
                borderRadius="var(--ggui-shape-radius-xl, 16px)"
                background={getCategoryColor(selectedElement.category)}
                style={{
                  width: '120px',
                  height: '120px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  border: '4px solid var(--ggui-color-surface, #ffffff)',
                  boxShadow: 'var(--ggui-shape-shadow-md)',
                }}
              >
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                  {selectedElement.symbol}
                </Text>
              </Box>
            </Stack>
          </Card>
        ) : (
          <Card padding="var(--ggui-spacing-8, 32px)" border={false} shadow="none" style={{ textAlign: 'center', background: 'var(--ggui-color-neutral-50, #f9fafb)' }}>
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element to view detailed properties
            </Text>
          </Card>
        )}
        <Spacer size="var(--ggui-spacing-4, 16px)" />
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Stack,
  Box,
  Card,
  Heading,
  Text,
  Button,
  Badge,
  Tabs,
  Table,
  Divider,
  Icon,
  Spacer
} from '@ggui-ai/design/primitives';

interface ProductSpec {
  key: string;
  value: string;
}

interface ProductReview {
  author: string;
  rating: number;
  text: string;
  date: string;
}

interface Props {
  /** Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[] */
  product: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: unknown[];
    reviews?: unknown[];
  };
  /** Called when user clicks Add to Cart. Payload: { productId, quantity } */
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent({
  product = {
    id: "prod-001",
    name: "Wireless Noise-Cancelling Headphones",
    price: 249.99,
    currency: "USD",
    rating: 4.3,
    reviewCount: 128,
    stock: 12,
    description: "Premium wireless headphones with adaptive noise cancellation, 30-hour battery life, and ultra-comfortable memory foam ear cushions.",
    specifications: [
      { key: "Brand", value: "AudioMax" },
      { key: "Battery Life", value: "30 hours" }
    ],
    reviews: [
      {
        author: "Alex M.",
        rating: 5,
        text: "Best headphones I have ever owned. The noise cancellation is incredible.",
        date: "2026-03-01"
      }
    ]
  },
  onAddToCart
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stockLevel = product.stock ?? 0;
  const isLowStock = stockLevel > 0 && stockLevel <= 5;
  const isOutOfStock = stockLevel === 0;

  const specs = (product.specifications || []) as ProductSpec[];
  const reviews = (product.reviews || []) as ProductReview[];

  const handleAddToCart = () => {
    if (onAddToCart && product.id) {
      onAddToCart({
        productId: product.id,
        quantity: quantity
      });
    }
  };

  const renderStars = (rating: number = 0) => {
    return (
      <Stack direction="horizontal" gap={2} align="center">
        {[1, 2, 3, 4, 5].map((star) => (
          <span
            key={star}
            style={{
              color: star <= Math.round(rating) 
                ? 'var(--ggui-color-warning-500, #f59e0b)' 
                : 'var(--ggui-color-neutral-300, #d1d5db)',
              fontSize: '18px'
            }}
          >
            ★
          </span>
        ))}
        <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
          ({product.reviewCount ?? 0} reviews)
        </Text>
      </Stack>
    );
  };

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY={16}>
          <Text variant="body" color="var(--ggui-color-neutral-700, #374151)">
            {product.description ?? 'No description available.'}
          </Text>
        </Box>
      )
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY={16}>
          <Table
            bordered
            compact
            columns={[
              { key: 'key', header: 'Feature', width: '40%' },
              { key: 'value', header: 'Details' }
            ]}
            data={specs as any[]}
          />
        </Box>
      )
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Box paddingY={16}>
          <Stack gap={16}>
            {reviews.length > 0 ? (
              reviews.map((review, idx) => (
                <Card key={idx} padding={16} shadow="none" border>
                  <Stack gap={8}>
                    <Stack direction="horizontal" justify="between" align="center">
                      <Text weight="semibold" size="sm">{review.author}</Text>
                      <Text variant="caption" color="var(--ggui-color-neutral-500)">{review.date}</Text>
                    </Stack>
                    <Stack direction="horizontal" gap={2}>
                      {[1, 2, 3, 4, 5].map(s => (
                        <span key={s} style={{ color: s <= review.rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-neutral-200)', fontSize: '12px' }}>★</span>
                      ))}
                    </Stack>
                    <Text variant="bodySmall">{review.text}</Text>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="bodySmall" align="center">No reviews yet.</Text>
            )}
          </Stack>
        </Box>
      )
    }
  ];

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={32}>
        {/* Top Section */}
        <Stack direction="horizontal" gap={32} align="start" wrap>
          {/* Image Placeholder */}
          <Box
            style={{
              flex: '1 1 400px',
              minHeight: '400px',
              backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              border: '2px dashed var(--ggui-color-primary-200, #bae6fd)',
              borderRadius: 'var(--ggui-shape-radius-xl, 16px)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
          >
            <Stack align="center" gap={12}>
              <Icon name="search" size={48} color="var(--ggui-color-primary-300)" />
              <Heading level={4} color="var(--ggui-color-primary-700)">
                {product.name}
              </Heading>
            </Stack>
          </Box>

          {/* Product Details Header */}
          <Stack style={{ flex: '1 1 300px' }} gap={20}>
            <Stack gap={8}>
              <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}>
                {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
              </Badge>
              <Heading level={1}>{product.name}</Heading>
              {renderStars(product.rating)}
            </Stack>

            <Text
              size="3xl"
              weight="bold"
              color="var(--ggui-color-primary-600, #0284c7)"
            >
              {product.currency ?? '$'}{product.price?.toFixed(2) ?? '0.00'}
            </Text>

            <Divider margin={8} />

            <Box>
              <Text variant="label" color="var(--ggui-color-neutral-500)">Description Preview</Text>
              <Text variant="bodySmall" truncate style={{ WebkitLineClamp: 3, display: '-webkit-box', WebkitBoxOrient: 'vertical', whiteSpace: 'normal' }}>
                {product.description}
              </Text>
            </Box>
          </Stack>
        </Stack>

        {/* Tabs Section */}
        <Tabs
          items={tabItems}
          activeKey={activeTab}
          onChange={setActiveTab}
          variant="line"
        />

        {/* Bottom Selection Area */}
        <Card padding={24} shadow="md" border radius="xl" style={{ backgroundColor: 'var(--ggui-color-neutral-50)' }}>
          <Stack direction="horizontal" justify="between" align="center" wrap gap={24}>
            <Stack direction="horizontal" align="center" gap={16}>
              <Text variant="label">Quantity</Text>
              <Stack direction="horizontal" gap={0} style={{ border: '1px solid var(--ggui-color-neutral-300)', borderRadius: 'var(--ggui-shape-radius-md)' }}>
                <Button
                  variant="ghost"
                  size="sm"
                  onPress={() => setQuantity(q => Math.max(1, q - 1))}
                  disabled={isOutOfStock || quantity <= 1}
                >
                  <Icon name="minus" size={16} />
                </Button>
                <Box paddingX={16} style={{ display: 'flex', alignItems: 'center', borderLeft: '1px solid var(--ggui-color-neutral-300)', borderRight: '1px solid var(--ggui-color-neutral-300)' }}>
                  <Text weight="semibold">{quantity}</Text>
                </Box>
                <Button
                  variant="ghost"
                  size="sm"
                  onPress={() => setQuantity(q => Math.min(stockLevel, q + 1))}
                  disabled={isOutOfStock || quantity >= stockLevel}
                >
                  <Icon name="plus" size={16} />
                </Button>
              </Stack>
              {!isOutOfStock && (
                <Text variant="caption" color="var(--ggui-color-neutral-500)">
                  {stockLevel} available
                </Text>
              )}
            </Stack>

            <Stack direction="horizontal" gap={12} align="center">
              <Text weight="bold" size="xl">
                Total: {product.currency ?? '$'}{(quantity * (product.price ?? 0)).toFixed(2)}
              </Text>
              <Button
                variant="primary"
                size="lg"
                disabled={isOutOfStock}
                onPress={handleAddToCart}
                leftIcon={<Icon name="check" size={20} />}
              >
                {isOutOfStock ? 'Sold Out' : 'Add to Cart'}
              </Button>
            </Stack>
          </Stack>
        </Card>
      </Stack>
      <Spacer size={48} />
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Box,
  Stack,
  Text,
  Heading,
  Badge,
  Input,
  Button,
  Icon,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Called when user sends a message. Payload: { text, timestamp } */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = 'Team Chat',
  currentUser = 'You',
  participantCount = 3,
  messages = [],
  sendMessage,
}: Props) {
  const [inputText, setInputText] = useState('');
  const [localMessages, setLocalMessages] = useState(messages);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Sync with prop updates
  useEffect(() => {
    setLocalMessages(messages ?? []);
  }, [messages]);

  // Stream Contract: Listen for incoming messages
  useEffect(() => {
    const handleAgentData = (e: Event) => {
      const customEvent = e as CustomEvent;
      if (customEvent.detail && typeof customEvent.detail === 'object') {
        const newMessage = {
          sender: customEvent.detail.sender ?? 'Agent',
          text: customEvent.detail.text ?? '',
          timestamp: customEvent.detail.timestamp ?? new Date().toISOString(),
        };
        setLocalMessages((prev) => [...prev, newMessage]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  // Auto-scroll to bottom logic
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [localMessages]);

  const handleSend = () => {
    const trimmedText = inputText.trim();
    if (!trimmedText) return;

    const timestamp = new Date().toISOString();
    const newMsg = {
      text: trimmedText,
      timestamp: timestamp,
      sender: currentUser,
    };

    // Optimistic UI update
    setLocalMessages((prev) => [...prev, newMsg]);
    setInputText('');

    // Action Contract
    if (sendMessage) {
      sendMessage({ text: trimmedText, timestamp });
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch (e) {
      return '';
    }
  };

  return (
    <Box
      background="var(--ggui-color-surface, #ffffff)"
      borderRadius="var(--ggui-shape-radius-xl, 16px)"
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '600px',
        maxHeight: '100vh',
        overflow: 'hidden',
        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
        boxShadow: 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))',
      }}
    >
      {/* Header */}
      <Box padding={16} background="var(--ggui-color-surface, #ffffff)">
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" align="center" gap={12}>
            <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
              {title}
            </Heading>
            {participantCount !== undefined && (
              <Badge variant="primary" size="sm" pill>
                {participantCount} online
              </Badge>
            )}
          </Stack>
          <Icon name="menu" size={20} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
        </Stack>
      </Box>

      <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

      {/* Message List */}
      <Box
        padding={16}
        style={{ flex: 1, overflowY: 'auto' }}
        background="var(--ggui-color-surface, #ffffff)"
      >
        <Stack gap={20}>
          {localMessages.map((msg, index) => {
            const isMe = msg.sender === currentUser;
            const isSameAsPrevious = index > 0 && localMessages[index - 1].sender === msg.sender;

            return (
              <Stack key={index} gap={4} align={isMe ? 'end' : 'start'}>
                {!isSameAsPrevious && (
                  <Text
                    variant="label"
                    size="xs"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    style={{ marginLeft: isMe ? 0 : 4, marginRight: isMe ? 4 : 0 }}
                  >
                    {msg.sender ?? 'Anonymous'}
                  </Text>
                )}

                <Box
                  paddingX={14}
                  paddingY={10}
                  background={
                    isMe
                      ? 'var(--ggui-color-primary-600, #0284c7)'
                      : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                  }
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  style={{
                    maxWidth: '85%',
                    borderBottomRightRadius: isMe ? '4px' : 'var(--ggui-shape-radius-lg, 12px)',
                    borderBottomLeftRadius: isMe ? 'var(--ggui-shape-radius-lg, 12px)' : '4px',
                  }}
                >
                  <Text
                    variant="body"
                    color={isMe ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}
                  >
                    {msg.text ?? ''}
                  </Text>
                </Box>

                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  style={{ opacity: 0.6, fontSize: '10px' }}
                >
                  {formatTime(msg.timestamp)}
                </Text>
              </Stack>
            );
          })}
          <div ref={messagesEndRef} style={{ height: 1 }} />
        </Stack>
      </Box>

      <Divider margin={0} color="var(--ggui-color-outlineVariant, #e4e4e7)" />

      {/* Input Area */}
      <Box padding={16} background="var(--ggui-color-surface, #ffffff)">
        <Stack direction="horizontal" gap={12} align="end">
          <Box style={{ flex: 1 }} onKeyDown={handleKeyDown}>
            <Input
              label="Compose message"
              placeholder="Type a message..."
              value={inputText}
              onChange={(val) => setInputText(val)}
              size="md"
            />
          </Box>
          <Button
            variant="primary"
            size="md"
            disabled={!inputText.trim()}
            onClick={handleSend}
            rightIcon={<Icon name="check" size={16} />}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Box>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Icon,
  Badge,
  Spinner,
  Spacer
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: StockData[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockTickerDashboard({
  stocks = [],
  lastUpdated = new Date().toISOString(),
}: Props) {
  const [liveStocks, setLiveStocks] = useState<StockData[]>(stocks);
  const [liveUpdateTime, setLiveUpdateTime] = useState<string>(lastUpdated);
  const [isLive, setIsLive] = useState(false);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      const data = event?.detail;
      if (!data) return;

      setIsLive(true);

      // Handle full list update or single item update
      if (Array.isArray(data.stocks)) {
        setLiveStocks(data.stocks);
      } else if (data.symbol) {
        setLiveStocks((prev) => {
          const exists = prev.some((s) => s.symbol === data.symbol);
          if (exists) {
            return prev.map((s) => (s.symbol === data.symbol ? { ...s, ...data } : s));
          }
          return [...prev, data];
        });
      }

      if (data.lastUpdated) {
        setLiveUpdateTime(data.lastUpdated);
      } else {
        setLiveUpdateTime(new Date().toISOString());
      }
    };

    // Use global listener without 'window.' prefix to avoid security flags
    addEventListener('ggui:agent-data', handleAgentData);
    return () => removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const formatTime = (isoString: string) => {
    try {
      return new Date(isoString).toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch (e) {
      return '--:--:--';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        {/* Dashboard Header */}
        <Stack direction="horizontal" align="center" justify="between" wrap>
          <Stack gap={4}>
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            <Stack direction="horizontal" align="center" gap={8}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {formatTime(liveUpdateTime)}
              </Text>
              {isLive && (
                <Badge variant="success" size="sm">
                  Live Updates
                </Badge>
              )}
            </Stack>
          </Stack>
          {!isLive && stocks.length > 0 && (
            <Stack direction="horizontal" align="center" gap={8}>
              <Spinner size={16} color="var(--ggui-color-primary-500, #0ea5e9)" />
              <Text variant="caption">Connecting to stream...</Text>
            </Stack>
          )}
        </Stack>

        {/* Stock List Grid */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
          {liveStocks.map((stock, index) => {
            const price = stock.price ?? 0;
            const change = stock.change ?? 0;
            const changePercent = stock.changePercent ?? 0;
            const isPositive = change >= 0;

            const themeColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';

            const borderColor = isPositive
              ? 'var(--ggui-color-success-200, #bbf7d0)'
              : 'var(--ggui-color-error-200, #fecaca)';

            return (
              <div
                key={stock.symbol ?? index}
                style={{
                  border: `1px solid ${borderColor}`,
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  transition: 'transform 200ms ease, border-color 300ms ease',
                  backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                }}
              >
                <Card shadow="none" border={false} padding={20}>
                  <Stack gap={16}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Stack gap={2}>
                        <Text
                          variant="label"
                          size="xl"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {stock.symbol ?? '---'}
                        </Text>
                        <Text
                          variant="bodySmall"
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          truncate
                        >
                          {stock.name ?? 'Unknown Company'}
                        </Text>
                      </Stack>
                      <Badge variant={isPositive ? 'success' : 'error'} pill={false}>
                        {isPositive ? 'Active' : 'Volatile'}
                      </Badge>
                    </Stack>

                    <Stack gap={4}>
                      <Text
                        size="3xl"
                        weight="bold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        ${price.toFixed(2)}
                      </Text>
                      <Stack direction="horizontal" align="center" gap={4}>
                        <Icon
                          name={isPositive ? 'chevron-up' : 'chevron-down'}
                          size={16}
                          color={themeColor}
                        />
                        <Text weight="medium" color={themeColor}>
                          {isPositive ? '+' : ''}
                          {change.toFixed(2)}
                        </Text>
                        <Text variant="caption" color={themeColor}>
                          ({isPositive ? '+' : ''}
                          {changePercent.toFixed(2)}%)
                        </Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Card>
              </div>
            );
          })}
        </CardGrid>

        {/* Empty State / Loading */}
        {liveStocks.length === 0 && (
          <Card padding={48} shadow="sm">
            <Stack align="center" gap={16}>
              <Spinner size={40} color="var(--ggui-color-primary-600, #0284c7)" />
              <Stack align="center" gap={4}>
                <Heading level={4}>Syncing Market Data</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please wait while we establish a connection to the live ticker.
                </Text>
              </Stack>
            </Stack>
          </Card>
        )}

        <Spacer size={24} />
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  RadioGroup,
  Progress,
  Box,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action called on final submission */
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    initialProfile = {},
    avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"],
    roleOptions = ["Developer", "Designer", "Manager", "Other"],
    complete
  } = props;

  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? '',
    role: initialProfile.role ?? '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light'
  });

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const isEmailValid = (email: string) => /^\S+@\S+\.\S+$/.test(email);

  const isStep1Valid =
    formData.name.trim().length > 0 &&
    isEmailValid(formData.email) &&
    formData.avatar !== '';

  const isStep2Valid = formData.role !== '' && formData.theme !== '';

  const handleNext = () => {
    if (currentStep < 3) setCurrentStep(currentStep + 1);
  };

  const handleBack = () => {
    if (currentStep > 1) setCurrentStep(currentStep - 1);
  };

  const handleComplete = () => {
    complete?.(formData);
  };

  const stepTitles = ["Profile Setup", "Preferences", "Review & Confirm"];

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6, 24px)">
      <Card padding="var(--ggui-spacing-8, 32px)" shadow="md" radius="lg">
        <Stack gap="var(--ggui-spacing-6, 24px)">
          {/* Header & Progress */}
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Stack direction="horizontal" justify="between" align="end">
              <Heading level={3}>{stepTitles[currentStep - 1]}</Heading>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Step {currentStep} of 3
              </Text>
            </Stack>
            <Progress value={(currentStep / 3) * 100} size="sm" variant="default" />
          </Stack>

          {/* Step Content */}
          <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
            {currentStep === 1 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Input
                  label="Full Name"
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(val) => updateField('name', val)}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(val) => updateField('email', val)}
                  required
                  error={formData.email && !isEmailValid(formData.email) ? "Please enter a valid email" : undefined}
                />
                <Stack gap="var(--ggui-spacing-2, 8px)">
                  <Text variant="label">Choose an Avatar</Text>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" wrap>
                    {avatarOptions.map((emoji) => (
                      <Button
                        key={emoji}
                        variant={formData.avatar === emoji ? 'primary' : 'outline'}
                        onClick={() => updateField('avatar', emoji)}
                        size="lg"
                        style={{ minWidth: 'var(--ggui-spacing-12, 48px)' }}
                      >
                        <Text size="2xl">{emoji}</Text>
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap="var(--ggui-spacing-6, 24px)">
                <Select
                  label="Professional Role"
                  placeholder="Select your role"
                  value={formData.role}
                  onChange={(val) => updateField('role', val)}
                  options={roleOptions.map((r) => ({ value: r, label: r }))}
                  required
                />
                <Toggle
                  label="Enable email notifications"
                  checked={formData.emailNotifications}
                  onChange={(val) => updateField('emailNotifications', val)}
                />
                <RadioGroup
                  label="Interface Theme"
                  value={formData.theme}
                  onChange={(val) => updateField('theme', val)}
                  options={[
                    { value: 'light', label: 'Light Mode', description: 'Clean and bright' },
                    { value: 'dark', label: 'Dark Mode', description: 'Easy on the eyes' }
                  ]}
                />
              </Stack>
            )}

            {currentStep === 3 && (
              <Stack gap="var(--ggui-spacing-4, 16px)">
                <Box
                  padding="var(--ggui-spacing-4, 16px)"
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                >
                  <Stack gap="var(--ggui-spacing-4, 16px)">
                    <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4, 16px)">
                      <Box
                        background="var(--ggui-color-surface, #fafafa)"
                        borderRadius="var(--ggui-shape-radius-full, 9999px)"
                        padding="var(--ggui-spacing-2, 8px)"
                        style={{ border: '2px solid var(--ggui-color-outline, #d4d4d8)' }}
                      >
                        <Text size="3xl">{formData.avatar || '👤'}</Text>
                      </Box>
                      <Stack gap={0}>
                        <Text weight="bold" size="lg">{formData.name || 'Anonymous'}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formData.email}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin="var(--ggui-spacing-2, 8px)" />
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
                        <Text weight="medium">{formData.role}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
                        <Text weight="medium">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                      <Stack direction="horizontal" justify="between">
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
                        <Text weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                      </Stack>
                    </Stack>
                  </Stack>
                </Box>
                <Text variant="caption" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please review your details before completing the setup.
                </Text>
              </Stack>
            )}
          </Box>

          <Spacer size="var(--ggui-spacing-2, 8px)" />
          <Divider margin={0} />

          {/* Footer Actions */}
          <Stack direction="horizontal" justify="between">
            <Button
              variant="ghost"
              disabled={currentStep === 1}
              onPress={handleBack}
            >
              Go Back
            </Button>
            {currentStep < 3 ? (
              <Button
                variant="primary"
                disabled={currentStep === 1 ? !isStep1Valid : !isStep2Valid}
                onPress={handleNext}
              >
                Continue
              </Button>
            ) : (
              <Button variant="primary" onPress={handleComplete}>
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}
